#!/usr/bin/env python3
from pathlib import Path
import datetime, shutil, py_compile

CRM=Path("/home/admin/crm")
MAIN=CRM/"main.py"
MODULE=CRM/"auto_collect_new.py"
if not MAIN.exists(): raise SystemExit("ERROR: main.py not found")
if not MODULE.exists(): raise SystemExit("ERROR: auto_collect_new.py not found")
backup=CRM/f"main_backup_before_new_auto_collect_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.py"
shutil.copy2(MAIN, backup)
txt=MAIN.read_text(encoding="utf-8", errors="ignore")
routes='\n# ===== NEW AUTO COLLECT ROUTES START =====\n@app.get("/auto_collect_new", response_class=HTMLResponse)\ndef auto_collect_new(request: Request, background_tasks: BackgroundTasks):\n    if not is_login(request):\n        return RedirectResponse("/login", 303)\n    try:\n        username = request.cookies.get("crm_user")\n        role = get_user_role(username) or "sales"\n        if role != "admin":\n            return HTMLResponse("<h2>Access Denied</h2><p>Admin only.</p>")\n    except Exception:\n        pass\n\n    def _run_new_auto_collect():\n        import subprocess, json, datetime\n        from pathlib import Path\n        status_file = Path("/home/admin/crm/auto_collect_status.json")\n        log_file = Path("/home/admin/crm/auto_collect_new.log")\n        try:\n            status_file.write_text(json.dumps({"version":"NEW AUTO COLLECT MODULE","status":"Running","message":"Started from CRM route","updated":datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")}, ensure_ascii=False, indent=2), encoding="utf-8")\n            with log_file.open("a", encoding="utf-8") as f:\n                f.write("\\\\n===== STARTED FROM CRM /auto_collect_new =====\\\\n")\n            result = subprocess.run(["./venv/bin/python","auto_collect_new.py"], cwd="/home/admin/crm", stdout=open("/home/admin/crm/auto_collect_new.log","a"), stderr=open("/home/admin/crm/auto_collect_new.log","a"), timeout=1800)\n            if result.returncode != 0:\n                status_file.write_text(json.dumps({"version":"NEW AUTO COLLECT MODULE","status":"Error","message":f"Exit code {result.returncode}","updated":datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")}, ensure_ascii=False, indent=2), encoding="utf-8")\n        except Exception as e:\n            try:\n                status_file.write_text(json.dumps({"version":"NEW AUTO COLLECT MODULE","status":"Error","message":str(e),"updated":datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")}, ensure_ascii=False, indent=2), encoding="utf-8")\n                with log_file.open("a", encoding="utf-8") as f:\n                    f.write(f"\\\\nNEW AUTO COLLECT ERROR: {e}\\\\n")\n            except Exception:\n                pass\n\n    background_tasks.add_task(_run_new_auto_collect)\n    return HTMLResponse("""<h2>New Auto Collect Started</h2><p>新自动采集模块已启动。</p><p>只使用 Bing，不使用 DuckDuckGo。</p><p><a href=\'/auto_collect_new_log\'>View New Log</a></p><p><a href=\'/auto_collect_new_status\'>View New Status</a></p><p><a href=\'/\'>Back to CRM</a></p>""")\n\n@app.get("/auto_collect_new_log", response_class=HTMLResponse)\ndef auto_collect_new_log(request: Request):\n    if not is_login(request):\n        return RedirectResponse("/login", 303)\n    from pathlib import Path\n    p = Path("/home/admin/crm/auto_collect_new.log")\n    if not p.exists():\n        p.write_text("No new auto collect log yet.", encoding="utf-8")\n    text = p.read_text(encoding="utf-8", errors="ignore")[-20000:]\n    text = text.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")\n    return HTMLResponse(f"<h2>New Auto Collect Log</h2><p><a href=\'/auto_collect_new\'>Start New Auto Collect</a> | <a href=\'/\'>Back</a></p><pre style=\'white-space:pre-wrap;background:#111;color:#0f0;padding:20px;border-radius:10px;\'>{text}</pre>")\n\n@app.get("/auto_collect_new_status", response_class=HTMLResponse)\ndef auto_collect_new_status(request: Request):\n    if not is_login(request):\n        return RedirectResponse("/login", 303)\n    from pathlib import Path\n    import json\n    p = Path("/home/admin/crm/auto_collect_status.json")\n    if not p.exists():\n        p.write_text(json.dumps({"status":"Ready","message":"No run yet"}, ensure_ascii=False, indent=2), encoding="utf-8")\n    text = p.read_text(encoding="utf-8", errors="ignore")\n    safe = text.replace("&","&amp;").replace("<","&lt;").replace(">","&gt;")\n    return HTMLResponse(f"<h2>New Auto Collect Status</h2><p><a href=\'/auto_collect_new\'>Start New Auto Collect</a> | <a href=\'/auto_collect_new_log\'>Log</a> | <a href=\'/\'>Back</a></p><pre style=\'white-space:pre-wrap;background:#111;color:#0ff;padding:20px;border-radius:10px;\'>{safe}</pre>")\n# ===== NEW AUTO COLLECT ROUTES END =====\n'
if "NEW AUTO COLLECT ROUTES START" not in txt:
    txt += "\n" + routes + "\n"
MAIN.write_text(txt, encoding="utf-8")
py_compile.compile(str(MAIN), doraise=True)
py_compile.compile(str(MODULE), doraise=True)
print("OK: installed new independent auto collect routes")
print(f"Backup: {backup}")
print("Use: /auto_collect_new")
